package com.cho2hand.marketplace.entity.trust; import jakarta.persistence.*; import java.io.Serializable; import java.util.Objects;
@Embeddable public class SellerFollowId implements Serializable {@Column(name="follower_user_id") private Long follower;@Column(name="seller_user_id") private Long seller;protected SellerFollowId(){}public SellerFollowId(Long f,Long s){follower=f;seller=s;}public boolean equals(Object o){return o instanceof SellerFollowId v&&Objects.equals(follower,v.follower)&&Objects.equals(seller,v.seller);}public int hashCode(){return Objects.hash(follower,seller);}}
